searchData={"items":[{"type":"module","title":"ConcreteOptics","doc":"Mostly a re-export module for convenience. Includes all standard optics,\noptic constructors, derived capabilities and optic axioms.","ref":"ConcreteOptics.html"},{"type":"module","title":"ConcreteOptics.Algebra.Applicative","doc":"A module which defines an macro to generate types for an applicative interface.\nThe macro assumes that the caller module defines a type `t/1` for the applicatives\nvalues and three specs for functions named `pure`, `lift1` and `lift2`.","ref":"ConcreteOptics.Algebra.Applicative.html"},{"type":"module","title":"ConcreteOptics.Algebra.Applicative.Id","doc":"The identity applicative without a wrapper. all operations are essentially noop.","ref":"ConcreteOptics.Algebra.Applicative.Id.html"},{"type":"type","title":"ConcreteOptics.Algebra.Applicative.Id.t/1","doc":"","ref":"ConcreteOptics.Algebra.Applicative.Id.html#t:t/1"},{"type":"function","title":"ConcreteOptics.Algebra.Applicative.Id.lift1/2","doc":"","ref":"ConcreteOptics.Algebra.Applicative.Id.html#lift1/2"},{"type":"function","title":"ConcreteOptics.Algebra.Applicative.Id.lift2/3","doc":"","ref":"ConcreteOptics.Algebra.Applicative.Id.html#lift2/3"},{"type":"function","title":"ConcreteOptics.Algebra.Applicative.Id.pure/1","doc":"","ref":"ConcreteOptics.Algebra.Applicative.Id.html#pure/1"},{"type":"module","title":"ConcreteOptics.Core.Capabilities","doc":"TODO\nOptic s t sa tb -> Optic sa tb a b -> Optic s t a b","ref":"ConcreteOptics.Core.Capabilities.html"},{"type":"type","title":"ConcreteOptics.Core.Capabilities.over_t/4","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#t:over_t/4"},{"type":"type","title":"ConcreteOptics.Core.Capabilities.review_t/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#t:review_t/2"},{"type":"type","title":"ConcreteOptics.Core.Capabilities.to_list_t/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#t:to_list_t/2"},{"type":"type","title":"ConcreteOptics.Core.Capabilities.traverse_t/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#t:traverse_t/2"},{"type":"type","title":"ConcreteOptics.Core.Capabilities.view_t/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#t:view_t/2"},{"type":"function","title":"ConcreteOptics.Core.Capabilities.compose_over/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#compose_over/2"},{"type":"function","title":"ConcreteOptics.Core.Capabilities.compose_review/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#compose_review/2"},{"type":"function","title":"ConcreteOptics.Core.Capabilities.compose_to_list/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#compose_to_list/2"},{"type":"function","title":"ConcreteOptics.Core.Capabilities.compose_traverse/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#compose_traverse/2"},{"type":"function","title":"ConcreteOptics.Core.Capabilities.compose_view/2","doc":"TODO","ref":"ConcreteOptics.Core.Capabilities.html#compose_view/2"},{"type":"module","title":"ConcreteOptics.Core.Common","doc":"TODO [:view, :review, :over, :to_list, :traverse]","ref":"ConcreteOptics.Core.Common.html"},{"type":"module","title":"ConcreteOptics.Core.Compose","doc":"","ref":"ConcreteOptics.Core.Compose.html"},{"type":"function","title":"ConcreteOptics.Core.Compose.extract_fields!/1","doc":"","ref":"ConcreteOptics.Core.Compose.html#extract_fields!/1"},{"type":"macro","title":"ConcreteOptics.Core.Compose.generate_compose/4","doc":"","ref":"ConcreteOptics.Core.Compose.html#generate_compose/4"},{"type":"module","title":"ConcreteOptics.Iso.Axioms","doc":"Axioms that a lawful isomorphism should satisfy. These are meant to be\nused in property tests for custom isomorphisms constructed using `ConcreteOptics.Iso.new`.","ref":"ConcreteOptics.Iso.Axioms.html"},{"type":"function","title":"ConcreteOptics.Iso.Axioms.review_view/1","doc":"The isomorphism law which states that applying review and then view yields the original value.","ref":"ConcreteOptics.Iso.Axioms.html#review_view/1"},{"type":"function","title":"ConcreteOptics.Iso.Axioms.view_review/1","doc":"The isomorphism law which states that applying view and then review yields the original value.","ref":"ConcreteOptics.Iso.Axioms.html#view_review/1"},{"type":"module","title":"ConcreteOptics.Optics.Iso","doc":"Isomorphism as an optic.","ref":"ConcreteOptics.Optics.Iso.html"},{"type":"type","title":"ConcreteOptics.Optics.Iso.t/4","doc":"","ref":"ConcreteOptics.Optics.Iso.html#t:t/4"},{"type":"function","title":"ConcreteOptics.Optics.Iso.eq/0","doc":"TODO","ref":"ConcreteOptics.Optics.Iso.html#eq/0"},{"type":"function","title":"ConcreteOptics.Optics.Iso.invert_iso/1","doc":"TODO","ref":"ConcreteOptics.Optics.Iso.html#invert_iso/1"},{"type":"function","title":"ConcreteOptics.Optics.Iso.new/2","doc":"Constructs an isomorphism from given `view` and `review` functions.","ref":"ConcreteOptics.Optics.Iso.html#new/2"},{"type":"function","title":"ConcreteOptics.Optics.Iso.supported_capabilities/0","doc":"","ref":"ConcreteOptics.Optics.Iso.html#supported_capabilities/0"},{"type":"function","title":"ConcreteOptics.Optics.Iso.transport/2","doc":"The `transport!/2` function implements an idea known as _transport of structure_\nin universal algebra. Transporting a function means to move its implementation to a\ndifferent type by going back and forth between the types. The first argument of\n`transport!/2` needs to be an iso. Otherwise the function throws an `ArgumentError`\nexception.","ref":"ConcreteOptics.Optics.Iso.html#transport/2"},{"type":"extras","title":"Introduction","doc":"# Introduction to ConcreteOptics","ref":"intro.html"},{"type":"extras","title":"TL;DR - Introduction","doc":"Optics are general and composable constructions that allow bidirectional access to immutable data.\n\nHere is an example of an optic --a traversal to be more precise-- which focuses on positive elements with key `:a` inside a map inside a vector.\n\n```elixir\n#TODO\n```","ref":"intro.html#tl-dr"},{"type":"extras","title":"Implementation Idea - Introduction","doc":"There is a very general [definition](https://ncatlab.org/nlab/show/optic+%28in+computer+science%29) of optics which relies on a nontrivial amount of mathematical background. We will not be working with that here. Instead, we will take a more *concrete* approach and work with certain capabilities an optic can have. Behind the curtains, each optic will be a map of capabilities.\n\nAs a simple mental model, we can think of an optic connecting a *big* whole to a *small* part. Sometimes we say that the optic focuses on the small part. Here is a list of capabilities with their intuitive meanings:\n\n* **view**: Gives you the small part of the whole. Typically field accessors are views.\n* **to_list**: Very much like **view**, but instead of a single element it focuses on many --possibly zero-- elements.\n* **review**: Given an element of the small part, constructs a big whole. Typically sum type constructors are reviews.\n* **over**: Turns a transformation over the small part into a transformation of the whole.\n* **traverse**: Allows you to perform a \"structured for loop\" over the focus.\n\nThere are also formal laws we expect these capabilities to satisfy. You can find their precise formulations in the test modules.\n\nHere is a table which classifies optics in terms of their capabilities.\n\n|               |  view | to_list| review | over | traverse |\n| ------------- |:-----:|:------:|:------:|:----:|:--------:|\n| iso           |   ✓   |    ✓   |   ✓    |  ✓   |    ✓     |\n| lens          |   ✓   |    ✓   |        |  ✓   |    ✓     |\n| prism         |       |    ✓   |   ✓    |  ✓   |    ✓     |\n| traversal     |       |    ✓   |        |  ✓   |    ✓     |\n| getter        |   ✓   |    ✓   |        |      |          |\n| setter        |       |        |        |  ✓   |          |\n| fold          |       |    ✓   |        |      |          |\n\nWhen we compose two optics, we compose their corresponding capabilities. If a capability is not a common capability of the optics then it is lost. For instance composition of two optics of the same kind is another of the same kind. An optic and its composition with an isomorphism are of the same kind since isomorphisms have all the capabilities. But the composition of a prism and a lens is a traversal.","ref":"intro.html#implementation-idea"},{"type":"extras","title":"What is Missing - Introduction","doc":"There is a general notion of duality in optics where you change the roles of the whole and the piece. For instance the function `invert_iso` is an implementation of this idea. However, in this capability only formalism, it is not possible to invert, say, a prism twice and get the original prism. The system can certainly be expanded to support this, though.\n\nExotic optics like grates or achromatic lenses are not implemented because, well, they are exotic and implementing them  would require a change in the current design which is dead simple.","ref":"intro.html#what-is-missing"},{"type":"extras","title":"Showcase","doc":"# Showcase\n\n```elixir\ndefmodule ConcreteOpticsTest do\n  @moduledoc \"\"\"\n  This test file is a showcase of optics supported by the library\n  as well as an introduction to optics in general.\n  \"\"\"\n  use ExUnit.Case, async: true\n  use ExUnitProperties\n  use Numbers, overload_operators: true\n\n  # Isomorphisms\n  # ------------\n\n  # Isomorphisms allow us to change the representation of data\n  # without loosing information. Here is a simple example.\n\n  def celsius_fahrenheit do\n    celsius_to_fahrenheit = fn\n      {:celsius, c} -> {:fahrenheit, 32 + Ratio.new(9, 5) * c}\n    end\n\n    fahrenheit_to_celsius = fn\n      {:fahrenheit, f} -> {:celsius, (f - 32) * Ratio.new(5, 9)}\n    end\n\n    ConcreteOptics.new(celsius_to_fahrenheit, fahrenheit_to_celsius)\n  end\n\n  # Note that we use rational numbers to avoid rounding errors and\n  # tagging the temperature value with its unit for clarity. Since\n  # this is a custom isomorphism it is a good idea to test it. to achieve\n  # that we need a way to generate not too large rational numbers. Size\n  # restriction is to avoid under and overflow problems.\n\n  defmodule ConcreteOpticsTest.RationalGenerator do\n    require StreamData\n\n    def gen() do\n      gen all numerator <- StreamData.integer(-1000..1000),\n              denominator <- StreamData.integer(-1000..1000),\n              denominator != 0 do\n        Ratio.new(numerator, denominator)\n      end\n    end\n  end\n\n  alias ConcreteOpticsTest.RationalGenerator\n\n  property \"celsius_fahrenheit is an iso\" do\n    check all r <- RationalGenerator.gen() do\n      # We use the same rational number in both directions to speed up the test.\n      c = {:celsius, r}\n      f = {:fahrenheit, r}\n      assert ConcreteOptics.view_review(celsius_fahrenheit()).(c)\n      assert ConcreteOptics.review_view(celsius_fahrenheit()).(f)\n    end\n  end\n\n  # Now let us put this isomorphism in use. Consider the following function\n  # which is defined Celsius in mind.\n\n  def celsius_freezing?({:celsius, r}) do\n    Ratio.lt?(r, 0)\n  end\n\n  test \"celsius_freezing? works\" do\n    assert celsius_freezing?({:celsius, Ratio.new(-1, 100)})\n    assert !celsius_freezing?({:celsius, 0})\n    assert !celsius_freezing?({:celsius, Ratio.new(12, 77)})\n  end\n\n  # However, by using the iso celsius_fahrenheit we can use the same function\n  # on fahrenheit values by first converting fahrenheit to celsius.\n\n  def fahrenheit_freezing?(f) do\n    f |> celsius_fahrenheit().review.() |> celsius_freezing?()\n  end\n\n  test \"celsius_freezing? can be used with fahrenheit\" do\n    assert fahrenheit_freezing?({:fahrenheit, Ratio.new(30, 1)})\n    assert !fahrenheit_freezing?({:fahrenheit, Ratio.new(35, 1)})\n  end\n\n  # This is fine but not really interesting. For a slightly more interesting\n  # example, consider the following function.\n\n  def increase_celsius({:celsius, diff}) do\n    fn {:celsius, r} ->\n      {:celsius, Ratio.add(r, diff)}\n    end\n  end\nend\n```","ref":"showcase.html"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.38.4"}}